div.style:
width: 1920px;
height: 1080px;
display: flex;
flex-direction: column;
justify-content: center;
align-items: flex-start;
padding: 0 160px;
box-sizing: border-box;
font-family: 'Segoe UI', 'Noto Sans JP', sans-serif;
color: #f1f5f9;

p.style:
font-size: 28px;
font-weight: 500;
color: #818cf8;
letter-spacing: 0.15em;
text-transform: uppercase;
margin: 0 0 32px 0;

h1.style:
font-size: 96px;
font-weight: 700;
line-height: 1.15;
margin: 0 0 40px 0;
max-width: 1400px;
word-break: auto-phrase;

p.style:
font-size: 40px;
font-weight: 400;
color: #94a3b8;
margin: 0 0 80px 0;
max-width: 1200px;
line-height: 1.5;

div.style:
display: flex;
align-items: center;
gap: 40px;
font-size: 28px;
color: #475569;
